<?php


namespace Yeepay\Yop\Sdk\Service\Agentpay;


use PHPUnit\Framework\TestCase;
use Yeepay\Yop\Sdk\Config\AppSdkConfig;
use Yeepay\Yop\Sdk\Exception\YopClientException;
use Yeepay\Yop\Sdk\Service\Agentpay\Model as Model;

class AgentpayClientTest extends TestCase
{

    private static $client;

    public static function setUpBeforeClass()
    {
        // 常用以下两种方式构造client，根据自身情况选择其一
        // 1. 基于本地配置文件方式：支持绝对路径、相对路径(相对于根目录)，适用于将文件打包到项目中，一起部署
        $sdkConfigFile = "yop_sdk_config_default.json";
        self::$client = AgentpayClientBuilder::builder($sdkConfigFile)->build();

        // 2. 基于json串方式：适用于自定义配置来源，从其他存储加载(比如说数据库、配置中心等)
        //$sdkConfigJson = '{"app_key":"app_xxx","server_root":"https://openapi.yeepay.com/yop-center","yos_server_root":"https://yos.yeepay.com/yop-center","yop_public_key":[{"store_type":"string","cert_type":"RSA2048","value":""}],"isv_private_key":[{"store_type":"string","cert_type":"RSA2048","value":""}],"encrypt_key":"AWXI5fZGXmTFVHfjyzBMMrrk1IF9dCqGJt3JIZrKY90=","http_client":{"connect_timeout":3000,"read_timeout":30000,"max_conn_total":200,"max_conn_per_route":100}}';
        //self::$client = AgentpayClientBuilder::builder(new AppSdkConfig(\GuzzleHttp\json_decode($sdkConfigJson, true)))->build();
    }

    /**
     * 智能体支付意图注册(/rest/v1.0/agentpay/intent/register)
     *
     * @test
     */
    public function intentRegisterTest()
    {
        $request = new Model\IntentRegisterRequest();

        $request->setBody(new \Yeepay\Yop\Sdk\Service\Agentpay\Model\YPAgentPayIntentReqDTO());
        try{
            $response = self::$client->intentRegister($request);
            print_r($response->getResult());
        }catch (\Exception $e) {
            echo 'Exception when calling AgentpayClient->intentRegister: ', $e->getMessage(), PHP_EOL;
        }
    }
    /**
     * 智能体支付意图注册(/rest/v1.0/agentpay/intent/register)
     *
     * @test
     */
    public function intent_register_v1Test()
    {
        $request = new Model\IntentRegisterV1Request();

        $request->setBody(new \Yeepay\Yop\Sdk\Service\Agentpay\Model\YPAgentPayIntentReqDTO());
        try{
            $response = self::$client->intent_register_v1($request);
            print_r($response->getResult());
        }catch (\Exception $e) {
            echo 'Exception when calling AgentpayClient->intent_register_v1: ', $e->getMessage(), PHP_EOL;
        }
    }
}
